    52→        isMethod().and(isPublic()).and(named("execute")).and(takesArguments(0)),
    53→        GoogleHttpClientInstrumentation.class.getName() + "$GoogleHttpClientAdvice",
    54→        GoogleHttpClientInstrumentation.class.getName()
    55→            + "$GoogleHttpClientContextPropagationAdvice");
    56→
    57→    transformer.applyAdvices(
    58→        isMethod()
    59→            .and(isPublic())
    60→            .and(named("executeAsync"))
    61→            .and(takesArguments(1))
    62→            .and(takesArgument(0, (named("java.util.concurrent.Executor")))),
    63→        GoogleHttpClientInstrumentation.class.getName() + "$GoogleHttpClientAsyncAdvice",
    64→        GoogleHttpClientInstrumentation.class.getName()
