    68→  public static class GoogleHttpClientAdvice {
    69→    @Advice.OnMethodEnter(suppress = Throwable.class)
    70→    public static AgentScope methodEnter(
    71→        @Advice.This HttpRequest request, @Advice.Local("inherited") AgentSpan inheritedSpan) {
    72→      AgentSpan activeSpan = activeSpan();
    73→      // detect if span was propagated here by java-concurrent handling
    74→      // of async requests
    75→      if (null != activeSpan) {
    76→        // reference equality to check this instrumentation created the span,
    77→        // not some other HTTP client
    78→        if (HTTP_REQUEST == activeSpan.getOperationName()) {
    79→          inheritedSpan = activeSpan;
    80→          return null;
    81→        }
    82→      }
    83→      return activateSpan(DECORATE.prepareSpan(startSpan(HTTP_REQUEST), request));
    84→    }
    85→
    86→    @Advice.OnMethodExit(onThrowable = Throwable.class, suppress = Throwable.class)
    87→    public static void methodExit(
    88→        @Advice.Enter AgentScope scope,
    89→        @Advice.Local("inherited") AgentSpan inheritedSpan,
    90→        @Advice.Return final HttpResponse response,
    91→        @Advice.Thrown final Throwable throwable) {
    92→      try {
    93→        AgentSpan span = scope != null ? scope.span() : inheritedSpan;
    94→        DECORATE.onError(span, throwable);
    95→        DECORATE.onResponse(span, response);
    96→
    97→        DECORATE.beforeFinish(span);
    98→        span.finish();
    99→      } finally {
   100→        if (scope != null) {
   101→          scope.close();
   102→        }
   103→      }
   104→    }
   105→  }
