   115→    public static void methodExit(
   116→        @Advice.Enter AgentScope scope, @Advice.Thrown final Throwable throwable) {
   117→      try {
   118→        if (throwable != null) {
   119→          AgentSpan span = scope.span();
   120→          DECORATE.onError(span, throwable);
   121→          DECORATE.beforeFinish(span);
   122→          span.finish();
   123→        }
   124→      } finally {
