     9→import java.net.URI;
    10→import java.net.URISyntaxException;
    11→import java.util.regex.Pattern;
    12→
    13→public class GoogleHttpClientDecorator extends HttpClientDecorator<HttpRequest, HttpResponse> {
    14→  private static final Pattern URL_REPLACEMENT = Pattern.compile("%20");
    15→  public static final CharSequence GOOGLE_HTTP_CLIENT =
    16→      UTF8BytesString.create("google-http-client");
    17→  public static final GoogleHttpClientDecorator DECORATE = new GoogleHttpClientDecorator();
    18→  public static final CharSequence HTTP_REQUEST = UTF8BytesString.create(DECORATE.operationName());
    19→
    20→  @Override
    21→  protected String method(final HttpRequest httpRequest) {
    22→    return httpRequest.getRequestMethod();
    23→  }
    24→
    25→  @Override
    26→  protected URI url(final HttpRequest httpRequest) throws URISyntaxException {
    27→    // Google uses %20 (space) instead of "+" for spaces in the fragment
    28→    // Add "+" back for consistency with the other http client instrumentations
    29→    final String url = httpRequest.getUrl().build();
    30→    final String fixedUrl = URL_REPLACEMENT.matcher(url).replaceAll("+");
    31→    return URIUtils.safeParse(fixedUrl);
    32→  }
    33→
    34→  public AgentSpan prepareSpan(AgentSpan span, HttpRequest request) {
    35→    DECORATE.afterStart(span);
    36→    DECORATE.onRequest(span, request);
    37→    return span;
    38→  }
    39→
    40→  @Override
    41→  protected int status(final HttpResponse httpResponse) {
    42→    return httpResponse.getStatusCode();
    43→  }
    44→
    45→  @Override
    46→  protected String[] instrumentationNames() {
    47→    return new String[] {"google-http-client"};
    48→  }
    49→
    50→  @Override
    51→  protected CharSequence component() {
    52→    return GOOGLE_HTTP_CLIENT;
    53→  }
    54→
    55→  @Override
    56→  protected String getRequestHeader(HttpRequest request, String headerName) {
    57→    return request.getHeaders().getFirstHeaderStringValue(headerName);
    58→  }
    59→
    60→  @Override
    61→  protected String getResponseHeader(HttpResponse response, String headerName) {
    62→    return response.getHeaders().getFirstHeaderStringValue(headerName);
    63→  }
    64→}
